import { Button, Dialog, DialogActions, DialogContent, DialogTitle, Slider, Stack, Typography } from "@mui/material";
import React from "react";
import { styled } from '@mui/material/styles';
import { toast } from "react-hot-toast";

const iOSBoxShadow = '0 3px 1px rgba(0,0,0,0.1),0 4px 8px rgba(0,0,0,0.13),0 0 0 1px rgba(0,0,0,0.02)';

const IOSSlider = styled(Slider)(({ theme }) => ({
    color: theme.palette.mode === 'dark' ? '#3880ff' : '#3880ff',
    height: 2,
    padding: '15px 0',
    '& .MuiSlider-thumb': {
        height: 14,
        width: 14,
        backgroundColor: '#fff',
        boxShadow: iOSBoxShadow,
        transition: 'all 300ms cubic-bezier(0.25, 0.8, 0.25, 1)',
        '&:focus, &:hover, &.Mui-active': {
            width: 16,
            height: 16,
            boxShadow:
                '0 3px 1px rgba(0,0,0,0.1),0 4px 8px rgba(0,0,0,0.3),0 0 0 1px rgba(0,0,0,0.02)',
            // Reset on touch devices, it doesn't add specificity
            '@media (hover: none)': {
                boxShadow: iOSBoxShadow,
            },
        },
    },
    '& .MuiSlider-valueLabel': {
        fontSize: 12,
        fontWeight: 'normal',
        top: -6,
        backgroundColor: 'unset',
        color: theme.palette.text.primary,
        '&:before': {
            display: 'none',
        },
        '& *': {
            background: 'transparent',
            color: theme.palette.mode === 'dark' ? '#fff' : '#000',
        },
    },
    '& .MuiSlider-track': {
        border: 'none',
    },
    '& .MuiSlider-rail': {
        opacity: 0.5,
        backgroundColor: '#bfbfbf',
    },
    '& .MuiSlider-mark': {
        backgroundColor: '#bfbfbf',
        height: 8,
        width: 1,
        '&.MuiSlider-markActive': {
            opacity: 1,
            backgroundColor: 'currentColor',
        },
    },
}));

export default function DialogHandlingEditor({ open, onClose, VehicleStates, onSubmit, VehicleModel }) {

    const [HandlingOptions, setHandlingOptions] = React.useState([]);

    const CopyHandling = () => {
        const NewHandlingData = {};
        HandlingOptions.forEach(option => (NewHandlingData[option.id] = option.value));
        const handlingDataString = JSON.stringify(NewHandlingData);

        const handleCopy = (event) => {
            event.preventDefault();
            event.clipboardData.setData('text/plain', handlingDataString);
            toast.success('Copied Handling Data to Clipboard');
        };

        document.addEventListener('copy', handleCopy);
        document.execCommand('copy');
        document.removeEventListener('copy', handleCopy);
    };

    const HandleSaveData = () => {
        const NewHandlingData = {};

        HandlingOptions.forEach((option) => {
            NewHandlingData[option.id] = option.value;
        });

        onSubmit(NewHandlingData);
    }

    const HandleProgressChange = (optionID, newValue) => {
        setHandlingOptions((prev) => {
            const newOptions = [...prev];

            newOptions.forEach((option) => {
                if (option.id === optionID) {
                    option.value = newValue;
                }
            });

            return newOptions;
        });
    }

    React.useEffect(() => {
        setHandlingOptions(VehicleStates);
    }, [VehicleStates])

    return (
        <Dialog
            open={open}
            onClose={onClose}
            fullScreen
        >
            <DialogTitle>Handling Editor {VehicleModel}</DialogTitle>
            <DialogContent sx={{ minWidth: '44vh' }}>
                {
                    HandlingOptions.map((option, index) => (
                        <Stack key={option.id} direction={'column'} alignItems={'flex-start'} gap={2.5} mt={index !== 0 ? 1.5 : 0} width={'100%'} px={1}>
                            <Typography sx={{ userSelect: 'text' }} variant={'subtitle1'}>{option.label}</Typography>
                            <IOSSlider
                                aria-label={option.id}
                                min={option.min}
                                max={option.max}
                                step={option.step}
                                value={option.value || 0}
                                onChange={(event, newValue) => HandleProgressChange(option.id, newValue)}
                                valueLabelDisplay="on"
                            />
                        </Stack>
                    ))
                }
            </DialogContent>
            <DialogActions>
                <Button color={'error'} onClick={onClose}>Cancel</Button>
                <Button onClick={CopyHandling}>Copy</Button>
                <Button onClick={HandleSaveData}>Save</Button>
            </DialogActions>
        </Dialog>
    )
}