import React from "react";
import { Dialog, DialogTitle, DialogContent, DialogActions, Button, Typography, Stack, MenuItem, Menu } from "@mui/material";

export default function DialogPlayerInfo(props) {
    const [anchorEl, setAnchorEl] = React.useState(null);

    const ShowPlayerRoles = (event) => {
        setAnchorEl(event.currentTarget);
    }

    return (
        <React.Fragment>
            <Dialog open={props?.open} onClose={props?.onClose}>
                <DialogTitle>Player Info: {props.PlayerInfo?.name}</DialogTitle>
                <DialogContent sx={{ width: '50vh' }}>
                    <Stack direction={'column'} alignItems={'flex-start'} gap={1} width={'100%'}>
                        <Stack direction={'row'} alignItems={'center'} gap={1} width={'100%'}>
                            <Typography variant={'subtitle1'}>ID:</Typography>
                            <Typography variant={'subtitle2'} color={'text.secondary'}>{props.PlayerInfo?.id}</Typography>
                        </Stack>
                        <Stack direction={'row'} alignItems={'center'} gap={1} width={'100%'}>
                            <Typography variant={'subtitle1'}>Name:</Typography>
                            <Typography sx={{ userSelect: 'text' }} variant={'subtitle2'} color={'text.secondary'}>{props.PlayerInfo?.name}</Typography>
                        </Stack>
                        <Stack direction={'row'} alignItems={'center'} gap={1} width={'100%'}>
                            <Typography variant={'subtitle1'}>IP:</Typography>
                            <Typography sx={{ userSelect: 'text' }} variant={'subtitle2'} color={'text.secondary'}>{props.PlayerInfo?.ip}</Typography>
                        </Stack>
                        <Stack direction={'row'} alignItems={'center'} gap={1} width={'100%'}>
                            <Typography variant={'subtitle1'}>Permission:</Typography>
                            <Typography variant={'subtitle2'} color={'text.secondary'}>{props.PlayerInfo?.PlayerPermission}</Typography>
                        </Stack>
                        <Stack direction={'row'} alignItems={'center'} gap={1} width={'100%'}>
                            <Typography variant={'subtitle1'}>Session:</Typography>
                            <Typography variant={'subtitle2'} color={'text.secondary'}>{props.PlayerInfo?.session}</Typography>
                        </Stack>
                        <Stack direction={'row'} alignItems={'center'} gap={1} width={'100%'}>
                            <Typography variant={'subtitle1'}>Character Name:</Typography>
                            <Typography sx={{ userSelect: 'text' }} variant={'subtitle2'} color={'text.secondary'}>{props.PlayerInfo?.charName}</Typography>
                        </Stack>
                        <Stack direction={'row'} alignItems={'center'} gap={1} width={'100%'}>
                            <Typography variant={'subtitle1'}>CitizenID:</Typography>
                            <Typography sx={{ userSelect: 'text' }} variant={'subtitle2'} color={'text.secondary'}>{props.PlayerInfo?.citizenID}</Typography>
                        </Stack>
                        <Stack direction={'row'} alignItems={'center'} gap={1} width={'100%'}>
                            <Typography variant={'subtitle1'}>Cash:</Typography>
                            <Typography variant={'subtitle2'} color={'text.secondary'}>{props.PlayerInfo?.moneyCash?.toLocaleString('en-US', { style: 'currency', currency: 'USD' }) || ''}</Typography>
                        </Stack>
                        <Stack direction={'row'} alignItems={'center'} gap={1} width={'100%'}>
                            <Typography variant={'subtitle1'}>Bank:</Typography>
                            <Typography variant={'subtitle2'} color={'text.secondary'}>{props.PlayerInfo?.moneyBank?.toLocaleString('en-US', { style: 'currency', currency: 'USD' }) || ''}</Typography>
                        </Stack>
                        <Stack direction={'row'} alignItems={'center'} gap={1} width={'100%'}>
                            <Typography variant={'subtitle1'}>Job:</Typography>
                            <Typography variant={'subtitle2'} color={'text.secondary'}>{props.PlayerInfo?.jobName}</Typography>
                        </Stack>
                        <Stack direction={'row'} alignItems={'center'} gap={1} width={'100%'}>
                            <Typography variant={'subtitle1'}>Job Grade:</Typography>
                            <Typography variant={'subtitle2'} color={'text.secondary'}>{props.PlayerInfo?.jobGrade}</Typography>
                        </Stack>
                        <Stack direction={'row'} alignItems={'center'} gap={1} width={'100%'}>
                            <Typography variant={'subtitle1'}>Job Salary:</Typography>
                            <Typography variant={'subtitle2'} color={'text.secondary'}>{props.PlayerInfo?.jobSalary?.toLocaleString('en-US', { style: 'currency', currency: 'USD' }) || ''}</Typography>
                        </Stack>
                        <Stack direction={'row'} alignItems={'center'} gap={1} width={'100%'}>
                            <Typography variant={'subtitle1'}>Discord Username:</Typography>
                            <Typography sx={{ userSelect: 'text' }} variant={'subtitle2'} color={'text.secondary'}>{props.PlayerInfo?.discordUsername}</Typography>
                        </Stack>
                        <Stack direction={'row'} alignItems={'center'} gap={1} width={'100%'}>
                            <Typography variant={'subtitle1'}>Discord ID:</Typography>
                            <Typography sx={{ userSelect: 'text' }} variant={'subtitle2'} color={'text.secondary'}>{props.PlayerInfo?.discordID}</Typography>
                        </Stack>
                        <Stack direction={'row'} alignItems={'center'} gap={1} width={'100%'}>
                            <Typography variant={'subtitle1'}>Discord Roles:</Typography>
                            <Button onClick={ShowPlayerRoles} id="discord-roles-button" variant={'text'} size={'small'}>Show</Button>
                            <Menu
                                id="discord-roles-menu"
                                anchorEl={anchorEl}
                                open={Boolean(anchorEl)}
                                onClose={() => setAnchorEl(null)}
                                MenuListProps={{
                                    'aria-labelledby': 'discord-roles-button',
                                }}
                            >
                                {props.PlayerInfo?.discordRoles?.map((role, index) => (
                                    <MenuItem key={index} value={role}>{role}</MenuItem>
                                ))}
                            </Menu>
                        </Stack>
                    </Stack>
                </DialogContent>
                <DialogActions>
                    <Button onClick={props?.onClose}>Close</Button>
                </DialogActions>
            </Dialog>
        </React.Fragment>
    )
}