export default function MainMenu() {

    const [ItemsList, setItemsList] = React.useState([]);

    const [isLoading, setIsLoading] = React.useState(false);

    const [ShowMenuAdmin, setShowMenuAdmin] = React.useState(false);

    const [AdminData, setAdminData] = React.useState({});

    const [ShowPlayerInfo, setShowPlayerInfo] = React.useState(false);

    const [SelectedPlayerInfo, setSelectedPlayerInfo] = React.useState({});

    const [HandlingEditorData, setHandlingEditorData] = React.useState({
        showDialog: false,
    });

    const [LoadingPlayers, setLoadingPlayers] = React.useState(false);

    const [PlayersList, setPlayersList] = React.useState([
        {
            id: 1,
            name: 'Choy',
            session: 1,
            ping: 0,
        }
    ]);

    const [MainMenuState, setMainMenuState] = React.useState({});

    const [SelectedTab, setSelectedTab] = React.useState('Main');

    const CloseMenu = () => {
        axios.post('https://mrp-admin/CloseMenu');
        setShowMenuAdmin(false);
        setAdminData({});
        setMainMenuState({});
    }

    const HandleTabChange = (event, newValue) => {
        setSelectedTab(newValue);
    }

    const HandleSwitchChange = async (optionID) => {
        try {
            if (!MainMenuState.hasOwnProperty(optionID)) return toast.error('This option is not available yet.');
            setIsLoading(true);
            const response = await axios.post('https://mrp-admin/HandleMainMenuSwitch', { optionID, value: !MainMenuState[optionID] });
            setIsLoading(false);
            const { data } = response;
            setMainMenuState(data);
            //setMainMenuState({ ...MainMenuState, [optionID]: !MainMenuState[optionID] });
        } catch (err) {
            toast.error('Something went wrong, please try again later.')
        }
    }

    const HandleInputChange = (optionID, value = '') => {
        if (!MainMenuState.hasOwnProperty(optionID)) return toast.error('This option is not available yet.');
        setMainMenuState({ ...MainMenuState, [optionID]: value })
    };

    const HandleMainMenuButton = async (optionID) => {
        try {
            if (!MainMenuState.hasOwnProperty(optionID)) return toast.error('This option is not available yet.');
            setIsLoading(true);
            const response = await axios.post('https://mrp-admin/HandleMainMenuButton', { optionID, value: MainMenuState[optionID] });
            setIsLoading(false);
            const { data } = response;
            const { MO, success, rsp, closeMenu } = data;
            if (!success) return toast.error(rsp);
            if (closeMenu) CloseMenu();
            setMainMenuState(MO);
        } catch (err) {
            toast.error('Something went wrong, please try again later.')
        }
    }

    const GetCurrentVehicleHandling = async () => {
        try {
            setIsLoading(true);
            const response = await axios.get('https://mrp-admin/GetCurrentVehicleHandling');
            setIsLoading(false);
            const { data } = response;
            const { success, rsp, VehicleStates } = data;
            if (!success) return toast.error(rsp);
            setHandlingEditorData({ showDialog: true, VehicleStates });
        } catch (err) {
            setIsLoading(false);
            toast.error('Something went wrong, please try again later.')
        }
    }

    const HandleVehicleOption = async (optionID) => {
        try {
            setIsLoading(true);
            const response = await axios.post('https://mrp-admin/HandleVehicleOption', { optionID });
            setIsLoading(false);
            const { data } = response;
            const { success, rsp } = data;
            if (!success) return toast.error(rsp);
            toast.success(rsp);
        } catch (err) {
            setIsLoading(false);
            toast.error('Something went wrong, please try again later.')
        }
    }

    const HandleVehicleButton = (optionID) => {
        if (optionID === 'edit_vehicle_handling') {
            GetCurrentVehicleHandling();
        } else {
            HandleVehicleOption(optionID);
        }
    }

    const ClosePlayerInfo = () => {
        setShowPlayerInfo(false);
    }

    const HandleOtherPlayerActions = (optionID, playerID) => async () => {
        HandleCloseAlertDialog();
        try {
            setIsLoading(true);
            const response = await axios.post('https://mrp-admin/HandleOtherPlayerActions', { optionID, playerID });
            setIsLoading(false);
            const { data } = response;
            const { success, rsp } = data;
            if (!success) return toast.error(rsp);
            toast.success(rsp);
        } catch (err) {
            setIsLoading(false);
            toast.error('Something went wrong, please try again later.')
        }
    }

    const HandleOnlinePlayerClickEvent = (optionID, playerID) => {
        const FindOption = OnlinePlayersOptions.find(item => item.id === optionID);
        if (!FindOption) return toast.error('This option is not available yet.');
        const Player = PlayersList.find(item => item.id === playerID);
        if (!Player) return toast.error('This player is not available anymore.');
        if (optionID === 'player_info') {
            setSelectedPlayerInfo(Player);
            setShowPlayerInfo(true);
        } else if (optionID === 'ban_player') {
            return setShowAlertDialog({
                open: true,
                title: 'Are you sure?',
                content: `You want to ban ${Player.name}?`,
                onSubmit: HandleOtherPlayerActions(optionID, Player.id),
            });
        } else if (optionID === 'kick_player') {
            return setShowAlertDialog({
                open: true,
                title: 'Are you sure?',
                content: `You want to kick ${Player.name}?`,
                onSubmit: HandleOtherPlayerActions(optionID, Player.id),
            });
        } else if (optionID === 'kill_player') {
            return setShowAlertDialog({
                open: true,
                title: 'Are you sure?',
                content: `You want to kill ${Player.name}?`,
                onSubmit: HandleOtherPlayerActions(optionID, Player.id),
            })
        } else if (optionID === 'freeze_player') {
            return setShowAlertDialog({
                open: true,
                title: 'Are you sure?',
                content: `You want to freeze ${Player.name}?`,
                onSubmit: HandleOtherPlayerActions(optionID, Player.id),
            })
        } else {
            if (FindOption.close) CloseMenu();
            HandleOtherPlayerActions(optionID, Player.id)();
        }
    }

    const [ShowSpawnItemsDialog, setShowSpawnItemsDialog] = React.useState(false);

    const [ShowAlertDialog, setShowAlertDialog] = React.useState({ open: false });

    const HandleCloseAlertDialog = () => {
        setShowAlertDialog({ ...ShowAlertDialog, open: false });
    }

    const HandleBringAllPlayers = async () => {
        HandleCloseAlertDialog();
        try {
            setIsLoading(true);
            const response = await axios.post('https://mrp-admin/HandleBringAllPlayers');
            setIsLoading(false);
            const { data } = response;
            const { success, rsp } = data;
            if (!success) return toast.error(rsp);
            toast.success(rsp);
        } catch (err) {
            setIsLoading(false);
            toast.error('Something went wrong, please try again later.')
        }
    }

    const HandleReviveAllPlayers = () => {
        HandleCloseAlertDialog();
        toast.success('Reviving all players.')
    }

    const HandleHealAllPlayers = () => {
        HandleCloseAlertDialog();
        toast.success('Healing all players.')
    }

    const HandleClearAll = async () => {
        HandleCloseAlertDialog();
        axios.post('https://mrp-admin/HandleClearAll');
    }

    const CloseOpenGiveItemDialog = () => {
        setShowSpawnItemsDialog(!ShowSpawnItemsDialog);
    }

    const HandleMiscButton = (id) => {
        if (id === 'misc_spawn_items') {
            return CloseOpenGiveItemDialog();
        }
        if (id === 'misc_bring_all_players') {
            return setShowAlertDialog({
                open: true,
                title: 'Are you sure?',
                content: 'This will bring all players to you.',
                onSubmit: HandleBringAllPlayers,
            });
        }
        if (id === 'misc_revive_all_players') {
            return setShowAlertDialog({
                open: true,
                title: 'Are you sure?',
                content: 'This will revive all players.',
                onSubmit: HandleReviveAllPlayers,
            })
        }
        if (id === 'misc_heal_all_players') {
            return setShowAlertDialog({
                open: true,
                title: 'Are you sure?',
                content: 'This will heal all players.',
                onSubmit: HandleHealAllPlayers,
            })
        }
        if (id === 'misc_clear_all') {
            return setShowAlertDialog({
                open: true,
                title: 'Are you sure?',
                content: 'This will clear everything.',
                onSubmit: HandleClearAll,
            })
        }
    }

    const HandleHandlingDialogClosed = () => {
        setHandlingEditorData({ showDialog: false });
    }

    const SaveCurrentVehicleHandling = async (Data) => {
        HandleHandlingDialogClosed();
        try {
            setIsLoading(true);
            const response = await axios.post('https://mrp-admin/SaveCurrentVehicleHandling', { VehicleStates: Data });
            setIsLoading(false);
            const { data } = response;
            const { success, rsp } = data;
            if (!success) return toast.error(rsp);
            toast.success(rsp);
            CloseMenu();
        } catch (err) {
            setIsLoading(false);
            toast.error('Something went wrong, please try again later.')
        }
    }

    const HandleSpawnItem = async (Items, Amount) => {
        try {
            setIsLoading(true);
            const response = await axios.post('https://mrp-admin/HandleSpawnItem', { Items, Amount });
            setIsLoading(false);
            const { data } = response;
            const { success, rsp } = data;
            if (!success) return toast.error(rsp);
            toast.success(rsp, { duration: 10000 });
            CloseOpenGiveItemDialog();
        } catch (err) {
            setIsLoading(false);
            toast.error('Something went wrong, please try again later.')
        }
    }

    React.useEffect(() => {

        const NuiEventHandler = (event) => {
            const { action, show, AdminData, MainMenuOptions, InventoryItems } = event.data;
            if (action === 'OpenHideMenu') {
                setShowMenuAdmin(Boolean(show));
                setAdminData(AdminData);
                setMainMenuState(MainMenuOptions);
                setItemsList(InventoryItems)
            }
        }

        const KeyDownEvent = (event) => {
            if (event.key === 'Escape') {
                event.preventDefault();
                CloseMenu();
            }
        }

        const FetchPlayers = async () => {
            try {
                setLoadingPlayers(true);
                const response = await axios.get('https://mrp-admin/GetPlayers');
                setLoadingPlayers(false);
                const { data } = response;
                setPlayersList(data);
            } catch (err) {
                setLoadingPlayers(false);
                toast.error('Something went wrong, please try again later.')
            }
        }

        if (ShowMenuAdmin && SelectedTab === 'Players') {
            FetchPlayers();
        }

        window.addEventListener('keydown', KeyDownEvent);

        window.addEventListener('message', NuiEventHandler);

        return () => {
            window.removeEventListener('message', NuiEventHandler);
            window.removeEventListener('keydown', KeyDownEvent);
        }

    }, [SelectedTab, ShowMenuAdmin])

    return (
        <React.Fragment>
            <Backdrop
                sx={{
                    color: '#fff',
                    zIndex: 999999999999999
                }}
                open={ShowMenuAdmin && isLoading}
            >
                <CircularProgress color="inherit" />
            </Backdrop>
            {ShowMenuAdmin && AdminData?.permission && <Stack direction={'column'} alignItems={'center'} className="mainMenu" gap={1} py={1}>
                {HandlingEditorData.showDialog && <DialogHandlingEditor open={HandlingEditorData.showDialog} onClose={HandleHandlingDialogClosed} VehicleStates={HandlingEditorData.VehicleStates} onSubmit={SaveCurrentVehicleHandling} VehicleModel={HandlingEditorData.model} />}
                <DialogPlayerInfo PlayerInfo={SelectedPlayerInfo} open={ShowPlayerInfo} onClose={ClosePlayerInfo} />
                <DialogSpawnItems open={ShowSpawnItemsDialog} onClose={CloseOpenGiveItemDialog} ItemsList={ItemsList} onSubmit={HandleSpawnItem} />
                <AlertDialog open={ShowAlertDialog.open} onClose={HandleCloseAlertDialog} title={ShowAlertDialog.title} content={ShowAlertDialog.content} onSubmit={ShowAlertDialog.onSubmit} />
                <Stack direction={'row'} alignItems={'flex-end'} gap={1}>
                    <span style={{ color: 'white', fontSize: 30 }}>Choy Admin</span>
                    <span style={{ color: 'white', fontSize: 14, textTransform: 'uppercase' }}>{AdminData?.permission}</span>
                </Stack>
                <Tabs value={SelectedTab} onChange={HandleTabChange} sx={{
                    //Space between tabs
                    '& .MuiTabs-flexContainer': {
                        gap: 2,
                    },
                    '& .MuiTabs-indicator': {
                        backgroundColor: 'white'
                    }
                }}>
                    <Tab value={'Main'} label="Main" />
                    <Tab value={'Players'} label="Players" />
                    <Tab value={'Vehicle'} label="Vehicle" />
                    <Tab value={'Misc'} label='Misc' />
                </Tabs>
                <Stack direction={'column'} alignItems={'flex-start'} gap={1} sx={{ width: '100%', height: '100%', overflow: 'auto' }} px={1}>
                    {MainMenuOptions.map(option => (
                        <Slide direction={'down'} in={SelectedTab === 'Main'} {...({ timeout: 250 })} key={option.id} mountOnEnter unmountOnExit>
                            <Stack key={option.id} direction={'row'} alignItems={'center'} justifyContent={'space-between'} gap={1} p={1} width={'100%'}>
                                <Stack direction={'row'} alignItems={'center'} gap={2} width={'100%'}>
                                    {option.icon}
                                    <Stack direction={'column'} alignItems={'flex-start'} gap={0} width={'calc(100% - 15%)'}>
                                        <span style={{ color: 'white', fontSize: 14 }}>{option.name}</span>
                                        {option.type === 'switch'
                                            ?
                                            <span style={{ color: 'gray', fontSize: 12 }}>{option.description}</span>
                                            :
                                            <TextField type={option.typeOfInput} placeholder={option.placeholder} value={MainMenuState[option.id] || ''} onChange={(e) => HandleInputChange(option.id, e.target.value)} variant="standard" size={'small'} fullWidth />
                                        }
                                    </Stack>
                                </Stack>
                                {option.type === 'switch' ?
                                    <Switch checked={MainMenuState[option.id] || false} onChange={() => HandleSwitchChange(option.id)} inputProps={{ 'aria-label': option.name }} />
                                    :
                                    <Button variant="contained" color="inherit" size={'small'} style={{ width: 100 }} onClick={() => HandleMainMenuButton(option.id)}>{option.buttonText}</Button>
                                }
                            </Stack>
                        </Slide>
                    ))}
                    {SelectedTab === 'Players' && LoadingPlayers && <Stack direction={'row'} alignItems={'center'} justifyContent={'center'} width={'100%'} p={1}>
                        <CircularProgress color="inherit" />
                    </Stack>}
                    {!LoadingPlayers && PlayersList.length === 0 && <Stack direction={'row'} alignItems={'center'} justifyContent={'center'} width={'100%'} height={'100%'} px={2}>
                        <span style={{ color: 'white', fontSize: 20, textTransform: 'capitalize' }}>No players found.</span>
                    </Stack>}
                    {PlayersList.map((player, index) => (
                        <Slide direction={'down'} in={SelectedTab === 'Players'} {...({ timeout: (300 * index) })} key={player.id} mountOnEnter unmountOnExit>
                            <Accordion sx={{ width: '100%' }}>
                                <AccordionSummary
                                    expandIcon={<ExpandMoreIcon />}
                                    aria-controls="panel1a-content"
                                    id="panel1a-header"
                                    sx={{
                                        width: '100%',
                                        bgcolor: 'rgba(255, 255, 255, 0.1)',
                                    }}
                                >
                                    <Typography sx={{ width: '33%', flexShrink: 0 }}>
                                        {player.name}
                                    </Typography>
                                    <Typography sx={{ color: 'text.secondary' }}>ID : #{player.id} | Session: #{player.session} | Ping: {player.ping}</Typography>
                                </AccordionSummary>
                                <AccordionDetails>
                                    <List>
                                        {OnlinePlayersOptions.map(option => (
                                            <ListItem key={option.id} disablePadding sx={{ color: option.color || 'white' }}>
                                                <ListItemButton onClick={() => HandleOnlinePlayerClickEvent(option.id, player.id)}>
                                                    <ListItemIcon>
                                                        {option.icon}
                                                    </ListItemIcon>
                                                    <ListItemText primary={option.name} />
                                                </ListItemButton>
                                            </ListItem>
                                        ))}
                                    </List>
                                </AccordionDetails>
                            </Accordion>
                        </Slide>
                    ))}

                    {VehiclesOptions.map(option => (
                        <Slide direction={'down'} in={SelectedTab === 'Vehicle'} {...({ timeout: 500 })} key={option.id} mountOnEnter unmountOnExit>
                            <Stack key={option.id} direction={'row'} alignItems={'center'} justifyContent={'space-between'} gap={1} p={1} width={'100%'}>
                                <Stack direction={'row'} alignItems={'center'} gap={2} width={'100%'}>
                                    {option.icon}
                                    <Stack direction={'column'} alignItems={'flex-start'} gap={0} width={'calc(100% - 15%)'}>
                                        <span style={{ color: 'white', fontSize: 14 }}>{option.name}</span>
                                        <span style={{ color: 'gray', fontSize: 12 }}>{option.description}</span>
                                    </Stack>
                                </Stack>
                                <Button variant="contained" color="inherit" size={'small'} style={{ width: 100 }} onClick={() => HandleVehicleButton(option.id)}>{option.buttonText}</Button>
                            </Stack>
                        </Slide>
                    ))}

                    {/* Misc Options */}

                    {MiscOptions.map(option => (
                        <Slide key={option.id} direction={'down'} in={SelectedTab === 'Misc'} {...({ timeout: 500 })} mountOnEnter unmountOnExit>
                            <Stack direction={'row'} alignItems={'center'} justifyContent={'space-between'} gap={1} p={1} width={'100%'}>
                                <Stack direction={'row'} alignItems={'center'} gap={2} width={'100%'}>
                                    {option.icon}
                                    <Stack direction={'column'} alignItems={'flex-start'} gap={0} width={'calc(100% - 15%)'}>
                                        <span style={{ color: 'white', fontSize: 14 }}>{option.name}</span>
                                        <span style={{ color: 'gray', fontSize: 12 }}>{option.description}</span>
                                    </Stack>
                                </Stack>
                                <Button onClick={() => HandleMiscButton(option.id)} variant="contained" color="inherit" size={'small'} style={{ width: 100 }}>{option.buttonText}</Button>
                            </Stack>
                        </Slide>
                    ))}
                </Stack>
            </Stack>}
        </React.Fragment>
    )
}