import React from "react";
import { Autocomplete, Button, Checkbox, Dialog, DialogActions, DialogContent, DialogContentText, DialogTitle, TextField } from "@mui/material";
import CheckBoxOutlineBlankIcon from '@mui/icons-material/CheckBoxOutlineBlank';
import CheckBoxIcon from '@mui/icons-material/CheckBox';
import { toast } from "react-hot-toast";

const icon = <CheckBoxOutlineBlankIcon fontSize="small" />;
const checkedIcon = <CheckBoxIcon fontSize="small" />;

export default function DialogSpawnItems({ open, onClose, ItemsList, onSubmit }) {

    const [SelectedItems, setSelectedItems] = React.useState([]);

    const [Amount, setAmount] = React.useState(1);

    const HandleSubmit = () => {
        const IntAmount = parseInt(Amount);
        if (isNaN(IntAmount) || IntAmount < 1) return toast.error('Amount must be a number and greater than 0');
        if (SelectedItems.length === 0) return toast.error('You must select at least 1 item to spawn');
        onSubmit(SelectedItems, IntAmount);
    }

    return (
        <Dialog open={open} onClose={onClose}>
            <DialogTitle>Spawn Items</DialogTitle>
            <DialogContent sx={{ width: '50vh' }}>
                <DialogContentText>
                    You can spawn multiple items by selecting them in the list below. default amount is 1, you can change this by clicking on the number and typing in a new number.
                </DialogContentText>
                <Autocomplete
                    multiple
                    fullWidth
                    id={'give-item-autocomplete'}
                    options={ItemsList}
                    sx={{ width: '100%', mt: 1 }}
                    disableCloseOnSelect
                    value={SelectedItems}
                    onChange={(event, newValue) => {
                        setSelectedItems(newValue);
                    }}
                    placeholder={'Item Name'}
                    getOptionLabel={(option) => option.name}
                    renderOption={(props, option, { selected }) => (
                        <li {...props} key={option.spawn_name}>
                            <Checkbox
                                icon={icon}
                                checkedIcon={checkedIcon}
                                style={{ marginRight: 8 }}
                                checked={selected}
                            />
                            {option.name}
                        </li>
                    )}
                    limitTags={1}
                    renderInput={(params) => <TextField {...params} label='Items List' />}
                />
                <TextField sx={{ mt: 2 }} id={'give-item-amount'} label={'Amount'} type={'number'} value={Amount} onChange={(e) => setAmount(e.target.value)} fullWidth />
            </DialogContent>
            <DialogActions>
                <Button onClick={onClose}>Cancel</Button>
                <Button onClick={HandleSubmit}>Spawn</Button>
            </DialogActions>
        </Dialog>
    )
}